// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import org.junit.jupiter.api.Test;

class TupleExprJsonCodecTest {

	@Test
	void roundTripsTupleExprViaJsonPayload() {
		StatementPattern tupleExpr = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		TupleExprJsonCodec codec = new TupleExprJsonCodec();

		String encoded = codec.toJson(tupleExpr);
		TupleExpr decoded = codec.fromJson(encoded);

		assertThat(decoded).isInstanceOf(StatementPattern.class);
		assertThat(decoded.toString()).isEqualTo(tupleExpr.toString());
	}

	@Test
	void rejectsUnsupportedPayloadFormat() {
		TupleExprJsonCodec codec = new TupleExprJsonCodec();

		assertThatThrownBy(() -> codec.fromJson("{\"format\":\"nope\",\"payloadBase64\":\"abc\"}"))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessageContaining("Unsupported tuple expression payload format");
	}
}
